struct UnitTest {
  test_number: int32;
  assertion: Assertion;
}

enum Assertion {
  struct BytesEqual {
    actual: BytesExpression;
    expected: BytesExpression;
  }
  bytes_equal: BytesEqual;

  struct BytesIn {
    actual: BytesExpression;
    // The assertion is satisfied if this array contains the actual value.
    expected: [bytes];
  }
  bytes_in: BytesIn;

  struct StringEqual {
    actual: StringExpression;
    expected: StringExpression;
  }
  string_equal: StringEqual;

  struct StringIn {
    actual: StringExpression;
    // The assertion is satisfied if this array contains the actual value.
    expected: [string];
  }
  string_in: StringIn;

  struct ReserializeValue {
    value: TypedValue;
    expected_dense_json: [string];
    expected_readable_json: [string];
    alternative_jsons: [StringExpression];
    expected_bytes: [bytes];
    alternative_bytes: [BytesExpression];
    expected_type_descriptor: string?;
  }
  reserialize_value: ReserializeValue;

  struct ReserializeLargeString {
    num_chars: int32;
    expected_byte_prefix: bytes;
  }
  reserialize_large_string: ReserializeLargeString;

  struct ReserializeLargeArray {
    num_items: int32;
    expected_byte_prefix: bytes;
  }
  reserialize_large_array: ReserializeLargeArray;

  enum_a_from_json_is_constant: struct {
    actual: StringExpression;
    keep_unrecognized: bool;
  };

  enum_a_from_bytes_is_constant: struct {
    actual: BytesExpression;
    keep_unrecognized: bool;
  };

  enum_b_from_json_is_wrapper_b: struct {
    actual: StringExpression;
    expected: string;
    keep_unrecognized: bool;
  };

  enum_b_from_bytes_is_wrapper_b: struct {
    actual: BytesExpression;
    expected: string;
    keep_unrecognized: bool;
  };
}

enum StringExpression {
  literal: string;
  to_dense_json: TypedValue;
  to_readable_json: TypedValue;
}

enum BytesExpression {
  literal: bytes;
  to_bytes: TypedValue;
}

enum TypedValue {
  bool: bool;
  int32: int32;
  int64: int64;
  hash64: hash64;
  float32: float32;
  float64: float64;
  timestamp: timestamp;
  string: string;
  bytes: bytes;
  bool_optional: bool?;
  ints: [int32];
  point: Point;
  color: Color;
  my_enum: MyEnum;
  enum_a: EnumA;
  enum_b: EnumB;
  keyed_arrays: KeyedArrays;
  rec_struct: RecStruct;
  rec_enum: RecEnum;
  round_trip_dense_json: TypedValue;
  round_trip_readable_json: TypedValue;
  round_trip_bytes: TypedValue;
  point_from_json_keep_unrecognized: StringExpression;
  point_from_json_drop_unrecognized: StringExpression;
  point_from_bytes_keep_unrecognized: BytesExpression;
  point_from_bytes_drop_unrecognized: BytesExpression;
  color_from_json_keep_unrecognized: StringExpression;
  color_from_json_drop_unrecognized: StringExpression;
  color_from_bytes_keep_unrecognized: BytesExpression;
  color_from_bytes_drop_unrecognized: BytesExpression;
  my_enum_from_json_keep_unrecognized: StringExpression;
  my_enum_from_json_drop_unrecognized: StringExpression;
  my_enum_from_bytes_keep_unrecognized: BytesExpression;
  my_enum_from_bytes_drop_unrecognized: BytesExpression;
  enum_a_from_json_keep_unrecognized: StringExpression;
  enum_a_from_json_drop_unrecognized: StringExpression;
  enum_a_from_bytes_keep_unrecognized: BytesExpression;
  enum_a_from_bytes_drop_unrecognized: BytesExpression;
  enum_b_from_json_keep_unrecognized: StringExpression;
  enum_b_from_json_drop_unrecognized: StringExpression;
  enum_b_from_bytes_keep_unrecognized: BytesExpression;
  enum_b_from_bytes_drop_unrecognized: BytesExpression;
}

/// A point
struct Point {
  removed;
  /// x coordinate
  x: int32;
  removed;
  removed;
  y: int32;
  removed;
  color: Color;
}

struct Color {
  r: int32 = 0;
  g: int32 = 1;
  b: int32 = 2;
  removed 3;
}

/// my enum
enum MyEnum {
  /// all good
  OK = 1;
  color: Color = 4;
  bool: bool = 5;
  removed 2;
}

enum EnumA {
  A;
  OTHER;
}

enum EnumB {
  b: string;
  OTHER;
}

struct KeyedArrays {
  enum Weekday {
    MONDAY;
  }
  struct SubItem {
    weekday: Weekday;
  }
  struct Item {
    sub_item: SubItem;
  }
  items: [Item|sub_item.weekday.kind];
}

struct RecStruct {
  a: RecStruct;
  b: bool;
}

enum RecEnum {
  FOO;
  e: RecEnum;
}

